unsigned int mod_exp(unsigned int base, unsigned int exp, unsigned int mod) {
    if (mod == 0) return 0;
    unsigned int result = 1;
    base = base % mod;
    while (exp > 0) {
        if (exp % 2 == 1) result = (result * base) % mod;
        exp /= 2;
        base = (base * base) % mod;
    }
    return result;
}

