  if h : n = 0 then 0 else n % 10 + sum_digits (n / 10)
termination_by n
decreasing_by exact Nat.div_lt_self (Nat.pos_of_ne_zero h) (by omega)

def count_digits (n : Nat) : Nat :=
  if n = 0 then 1
  else
    let rec loop (val count : Nat) : Nat :=
      if val = 0 then count else loop (val / 10) (count + 1)
    loop n 0
termination_by n
